import heapq
import itertools
from abc import ABC, abstractmethod
from collections import deque
from collections.abc import Iterable, Iterator
from enum import Enum

from vllm.v1.core.sched.policy import (
    SchedulerPolicyPlugin,
    get_scheduler_policy_plugin,
)
from vllm.v1.request import Request


class SchedulingPolicy(Enum):
    """Enum for scheduling policies."""

    FCFS = "fcfs"
    PRIORITY = "priority"
    LENGTH_ONLY = "length_only"
    LTR = "ltr"
    MOE_AFFINITY = "moe_affinity"


class RequestQueue(ABC):
    """Abstract base class for request queues."""

    @abstractmethod
    def add_request(self, request: Request) -> None:
        """Add a request to the queue according to the policy."""
        pass

    @abstractmethod
    def pop_request(self) -> Request:
        """Pop a request from the queue according to the policy."""
        pass

    @abstractmethod
    def peek_request(self) -> Request:
        """Peek at the request at the front of the queue without removing it."""
        pass

    @abstractmethod
    def prepend_request(self, request: Request) -> None:
        """Prepend a request to the front of the queue."""
        pass

    @abstractmethod
    def prepend_requests(self, requests: "RequestQueue") -> None:
        """Prepend all requests from another queue to the front of this
        queue."""
        pass

    @abstractmethod
    def remove_request(self, request: Request) -> None:
        """Remove a specific request from the queue."""
        pass

    @abstractmethod
    def remove_requests(self, requests: Iterable[Request]) -> None:
        """Remove multiple specific requests from the queue."""
        pass

    @abstractmethod
    def __bool__(self) -> bool:
        """Check if queue has any requests."""
        pass

    @abstractmethod
    def __len__(self) -> int:
        """Get number of requests in queue."""
        pass

    @abstractmethod
    def __iter__(self) -> Iterator[Request]:
        """Iterate over the queue according to the policy."""
        pass


class FCFSRequestQueue(deque[Request], RequestQueue):
    """A first-come-first-served queue that supports deque operations."""

    def add_request(self, request: Request) -> None:
        """Add a request to the queue according to FCFS policy."""
        self.append(request)

    def pop_request(self) -> Request:
        """Pop a request from the queue according to FCFS policy."""
        return self.popleft()

    def peek_request(self) -> Request:
        """Peek at the next request in the queue without removing it."""
        if not self:
            raise IndexError("peek from an empty queue")
        return self[0]

    def prepend_request(self, request: Request) -> None:
        """Prepend a request to the front of the queue."""
        self.appendleft(request)

    def prepend_requests(self, requests: RequestQueue) -> None:
        """Prepend all requests from another queue to the front of this
        queue.

        Note: The requests will be prepended in reverse order of their
        appearance in the `requests` queue.
        """
        self.extendleft(requests)

    def remove_request(self, request: Request) -> None:
        """Remove a specific request from the queue."""
        self.remove(request)

    def remove_requests(self, requests: Iterable[Request]) -> None:
        """Remove multiple specific requests from the queue."""
        requests_to_remove = set(requests)
        filtered_requests = [req for req in self if req not in requests_to_remove]
        # deque does not support in-place filtering, so we need to clear
        # and extend
        self.clear()
        self.extend(filtered_requests)

    def __bool__(self) -> bool:
        """Check if queue has any requests."""
        return len(self) > 0

    def __len__(self) -> int:
        """Get number of requests in queue."""
        return super().__len__()

    def __iter__(self) -> Iterator[Request]:
        """Iterate over the queue according to FCFS policy."""
        return super().__iter__()


class PolicyRequestQueue(RequestQueue):
    """
    A policy-driven queue that supports heap operations.

    The policy plugin computes a stable sort key for each request; lower keys
    are scheduled earlier.
    """

    def __init__(self, policy: SchedulerPolicyPlugin) -> None:
        self._policy = policy
        self._counter = itertools.count()
        self._heap: list[tuple[tuple[object, ...], int, Request]] = []

    def _entry(self, request: Request) -> tuple[tuple[object, ...], int, Request]:
        return (self._policy.sort_key(request), next(self._counter), request)

    def _rebuild_heap(self, requests: Iterable[Request]) -> None:
        self._heap = [self._entry(request) for request in requests]
        heapq.heapify(self._heap)

    def add_request(self, request: Request) -> None:
        """Add a request to the queue according to the configured policy."""
        heapq.heappush(self._heap, self._entry(request))

    def pop_request(self) -> Request:
        """Pop a request from the queue according to the configured policy."""
        if not self._heap:
            raise IndexError("pop from empty heap")
        return heapq.heappop(self._heap)[2]

    def peek_request(self) -> Request:
        """Peek at the next request in the queue without removing it."""
        if not self._heap:
            raise IndexError("peek from empty heap")
        return self._heap[0][2]

    def prepend_request(self, request: Request) -> None:
        """Add a request to the queue according to the configured policy.

        Note: In a policy heap, there is no concept of prepending to the front.
        Requests are ordered by their policy key."""
        self.add_request(request)

    def prepend_requests(self, requests: RequestQueue) -> None:
        """Add all requests from another queue according to the configured policy.

        Note: In a policy heap, there is no concept of prepending to the front.
        Requests are ordered by their policy key."""
        for request in requests:
            self.add_request(request)

    def remove_request(self, request: Request) -> None:
        """Remove a specific request from the queue."""
        for idx, entry in enumerate(self._heap):
            if entry[2] is request:
                del self._heap[idx]
                heapq.heapify(self._heap)
                return
        raise ValueError(f"{request!r} is not in queue")

    def remove_requests(self, requests: Iterable[Request]) -> None:
        """Remove multiple specific requests."""
        requests_to_remove = requests if isinstance(requests, set) else set(requests)
        self._rebuild_heap(
            entry[2] for entry in self._heap if entry[2] not in requests_to_remove
        )

    def __bool__(self) -> bool:
        """Check if queue has any requests."""
        return bool(self._heap)

    def __len__(self) -> int:
        """Get number of requests in queue."""
        return len(self._heap)

    def __iter__(self) -> Iterator[Request]:
        """Iterate over the queue according to the configured policy."""
        heap_copy = self._heap[:]
        while heap_copy:
            yield heapq.heappop(heap_copy)[2]


class PriorityRequestQueue(PolicyRequestQueue):
    """
    A priority queue that supports heap operations.

    Requests with a smaller value of `priority` are processed first.
    If multiple requests have the same priority, the one with the earlier
    `arrival_time` is processed first.
    """

    def __init__(self) -> None:
        super().__init__(get_scheduler_policy_plugin(SchedulingPolicy.PRIORITY.value))


class LengthOnlyRequestQueue(PolicyRequestQueue):
    """
    A shortest-estimated-length-first queue.

    Estimated length is `num_prompt_tokens + max_tokens`; ties preserve prompt
    length and arrival order. This policy runs inside the vLLM scheduler rather
    than reordering requests at the client.
    """

    def __init__(self) -> None:
        super().__init__(
            get_scheduler_policy_plugin(SchedulingPolicy.LENGTH_ONLY.value)
        )


class LTRRequestQueue(PolicyRequestQueue):
    """
    A learning-to-rank request queue.

    Scores are provided by the configured LTR policy plugin. Lower scores are
    scheduled earlier; ties preserve length and arrival order.
    """

    def __init__(self) -> None:
        super().__init__(get_scheduler_policy_plugin(SchedulingPolicy.LTR.value))


class MoEAffinityRequestQueue(PolicyRequestQueue):
    """
    A MoE-locality-aware request queue.

    The heap uses a stable base key; the scheduler performs a dynamic top-K
    rerank against the current running batch before admitting a waiting request.
    """

    def __init__(self) -> None:
        super().__init__(
            get_scheduler_policy_plugin(SchedulingPolicy.MOE_AFFINITY.value)
        )


def create_request_queue(policy: SchedulingPolicy) -> RequestQueue:
    """Create request queue based on scheduling policy."""
    if policy == SchedulingPolicy.PRIORITY:
        return PriorityRequestQueue()
    elif policy == SchedulingPolicy.LENGTH_ONLY:
        return LengthOnlyRequestQueue()
    elif policy == SchedulingPolicy.LTR:
        return LTRRequestQueue()
    elif policy == SchedulingPolicy.MOE_AFFINITY:
        return MoEAffinityRequestQueue()
    elif policy == SchedulingPolicy.FCFS:
        return FCFSRequestQueue()
    else:
        raise ValueError(f"Unknown scheduling policy: {policy}")
